async (params, browser) => {
  // Open article page
  await browser.open(`${params.article_url}`)

  // Wait for article to load
  await browser.waitForSelector('#firstHeading, h1', 15000)

  // Let page render
  await browser.wait(1500)

  // Scroll to references section
  await browser.scroll({ direction: 'down', amount: 5000 })

  await browser.wait(2000)

  // Scroll further through references
  await browser.scroll({ direction: 'down', amount: 3000 })

  await browser.wait(1500)

  // Extract references
  const references_data = await browser.evaluate(`const titleEl = document.querySelector('#firstHeading, h1'); const references = []; const refEls = document.querySelectorAll('.references li, .reflist li, ol.references > li'); for (let i = 0; i < Math.min(refEls.length, 30); i++) { const el = refEls[i]; const text = el.textContent.trim(); const linkEl = el.querySelector('a.external, a[href^="http"]'); const citeEl = el.querySelector('.citation, cite'); references.push({ index: i + 1, text: text.substring(0, 500), url: linkEl ? linkEl.href : '', citation: citeEl ? citeEl.textContent.trim().substring(0, 300) : '' }); } const furtherReadingEls = []; const frSection = document.querySelector('#Further_reading, #Bibliography'); if (frSection) { let sibling = frSection.closest('h2') ? frSection.closest('h2').nextElementSibling : null; while (sibling && !sibling.matches('h2')) { if (sibling.matches('ul, ol')) { const items = sibling.querySelectorAll('li'); items.forEach(function(item) { furtherReadingEls.push(item.textContent.trim().substring(0, 300)); }); } sibling = sibling.nextElementSibling; } } return { title: titleEl ? titleEl.textContent.trim() : '', reference_count: references.length, references: references, further_reading: furtherReadingEls.slice(0, 10), url: window.location.href }`)

  return references_data
}
